PROCEDURE Encapsulate_Data(Application_Data, Dest_IP, Dest_Port)
BEGIN
    // Application Layer - Data created
    data = Application_Data

    // Transport Layer - Add TCP/UDP header (Segment)
    // Includes: Source Port, Dest Port, Sequence Number, Flags
    segment = CREATE_SEGMENT(data, Source_Port, Dest_Port, SEQ_NUM)

    // Network Layer - Add IP header (Packet)
    // Includes: Source IP, Dest IP, Protocol, TTL
    packet = CREATE_PACKET(segment, Source_IP, Dest_IP, PROTOCOL)

    // Data Link Layer - Add Ethernet header/trailer (Frame)
    // Includes: Source MAC, Dest MAC, FCS
    frame = CREATE_FRAME(packet, Source_MAC, Dest_MAC)

    // Physical Layer - Convert to bits for transmission
    bits = CONVERT_TO_BITS(frame)

    RETURN bits
END

PROCEDURE Decapsulate_Data(received_bits)
BEGIN
    // Reverse process at receiving end
    frame = CONVERT_FROM_BITS(received_bits)
    packet = REMOVE_FRAME_HEADER(frame)
    segment = REMOVE_IP_HEADER(packet)
    data = REMOVE_SEGMENT_HEADER(segment)

    RETURN data
END
